+        .args(["config", "history"])
+        .assert()
+        .success();
+}
+
+#[test]
+fn cli_config_history_json_output() {
+    let output = savant()
+        .args(["--json", "config", "history"])
+        .assert()
+        .success()
+        .get_output()
+        .stdout
+        .clone();
+
+    let json: serde_json::Value = serde_json::from_slice(&output).unwrap();
